/// Represents the types of sensitive data the module handles
enum SensitiveDataType: String {
    case userCredentials = "com.app.credentials"
    case paymentToken = "com.app.paymenttoken"
    case personalInfo = "com.app.personalinfo"
}

/// Errors that can occur during security operations
enum DataSecurityError: Error, LocalizedError {
    case encryptionFailed(String)
    case decryptionFailed(String)
    case keyGenerationFailed
    case keyStorageFailed(OSStatus)
    case keyRetrievalFailed(OSStatus)
    case keyDeletionFailed(OSStatus)
    case dataConversionFailed
    case invalidSealedBox

    var errorDescription: String? {
        switch self {
        case .encryptionFailed(let msg): return "Encryption failed: \(msg)"
        case .decryptionFailed(let msg): return "Decryption failed: \(msg)"
        case .keyGenerationFailed: return "Failed to generate encryption key"
        case .keyStorageFailed(let status): return "Failed to store key in Keychain (status: \(status))"
        case .keyRetrievalFailed(let status): return "Failed to retrieve key from Keychain (status: \(status))"
        case .keyDeletionFailed(let status): return "Failed to delete key from Keychain (status: \(status))"
        case .dataConversionFailed: return "Failed to convert data"
        case .invalidSealedBox: return "Invalid sealed box data"
        }
    }
