// MARK: - Keychain Key Manager

/// Manages encryption keys securely using the iOS Keychain
final class KeychainKeyManager {

    static let shared = KeychainKeyManager()

    private let keychainServicePrefix = "com.app.datasecurity"

    private init() {}

    // MARK: - Key Retrieval or Generation

    /// Retrieves an existing AES-256 key from the Keychain for the given data type,
    /// or generates a new one and stores it securely.
    func retrieveOrGenerateKey(for dataType: SensitiveDataType) throws -> SymmetricKey {
        if let existingKey = try? retrieveKey(for: dataType) {
            return existingKey
        }

        let newKey = SymmetricKey(size: .bits256)
        try storeKey(newKey, for: dataType)
        return newKey
    }

    // MARK: - Store Key in Keychain

    private func storeKey(_ key: SymmetricKey, for dataType: SensitiveDataType) throws {
        let keyData = key.withUnsafeBytes { Data($0) }

        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServicePrefix,
            kSecAttrAccount as String: dataType.rawValue,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]

        // Delete any existing key first
        SecItemDelete(query as CFDictionary)

        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw DataSecurityError.keyStorageFailed(status)
        }
    }

    // MARK: - Retrieve Key from Keychain

    private func retrieveKey(for dataType: SensitiveDataType) throws -> SymmetricKey {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServicePrefix,
            kSecAttrAccount as String: dataType.rawValue,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)

        guard status == errSecSuccess, let keyData = result as? Data else {
            throw DataSecurityError.keyRetrievalFailed(status)
        }

        return SymmetricKey(data: keyData)
    }

    // MARK: - Delete Key from Keychain

    func deleteKey(for dataType: SensitiveDataType) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServicePrefix,
            kSecAttrAccount as String: dataType.rawValue
        ]

        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw DataSecurityError.keyDeletionFailed(status)
        }
    }

    /// Deletes all stored keys
    func deleteAllKeys() throws {
        for dataType in [SensitiveDataType.userCredentials, .paymentToken, .personalInfo] {
            try deleteKey(for: dataType)
        }
    }
}

// MARK: - Data Security Module

/// Main module for encrypting and decrypting sensitive data using AES-256-GCM
/// (authenticated encryption via CryptoKit).
///
/// Keys are stored in the iOS Keychain — never hardcoded in source.
/// Each data type (credentials, payment tokens, personal info) uses its own key.
final class DataSecurityModule {

    static let shared = DataSecurityModule()

    private let keyManager = KeychainKeyManager.shared

    private init() {}

    // MARK: - Encrypt Data

    /// Encrypts raw `Data` using AES-256-GCM (authenticated encryption).
    /// Returns the combined nonce + ciphertext + tag as a single `Data` blob.
    func encrypt(data: Data, for dataType: SensitiveDataType) throws -> Data {
        let key = try keyManager.retrieveOrGenerateKey(for: dataType)

        do {
            // AES-GCM provides authenticated encryption (confidentiality + integrity)
            // CryptoKit generates a cryptographically secure random nonce automatically
            let sealedBox = try AES.GCM.seal(data, using: key)

            guard let combined = sealedBox.combined else {
                throw DataSecurityError.invalidSealedBox
            }

            return combined
        } catch let error as DataSecurityError {
            throw error
        } catch {
            throw DataSecurityError.encryptionFailed(error.localizedDescription)
        }
    }

    /// Encrypts a `String` using AES-256-GCM.
    func encrypt(string: String, for dataType: SensitiveDataType) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw DataSecurityError.dataConversionFailed
        }
        return try encrypt(data: data, for: dataType)
    }

    /// Encrypts a `Codable` object using AES-256-GCM.
    func encrypt<T: Codable>(object: T, for dataType: SensitiveDataType) throws -> Data {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(object)
        return try encrypt(data: data, for: dataType)
    }

    // MARK: - Decrypt Data

    /// Decrypts a combined AES-GCM sealed box back to raw `Data`.
    func decrypt(data: Data, for dataType: SensitiveDataType) throws -> Data {
        let key = try keyManager.retrieveOrGenerateKey(for: dataType)

        do {
            let sealedBox = try AES.GCM.SealedBox(combined: data)
            let decryptedData = try AES.GCM.open(sealedBox, using: key)
            return decryptedData
        } catch {
            throw DataSecurityError.decryptionFailed(error.localizedDescription)
        }
    }

    /// Decrypts data back to a `String`.
    func decryptToString(data: Data, for dataType: SensitiveDataType) throws -> String {
        let decryptedData = try decrypt(data: data, for: dataType)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw DataSecurityError.dataConversionFailed
        }
        return string
    }

    /// Decrypts data back to a `Codable` object.
    func decrypt<T: Codable>(data: Data, as type: T.Type, for dataType: SensitiveDataType) throws -> T {
        let decryptedData = try decrypt(data: data, for: dataType)
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(T.self, from: decryptedData)
    }

    // MARK: - Secure Random Data Generation

    /// Generates cryptographically secure random bytes using the platform security API.
    func generateSecureRandomData(byteCount: Int) throws -> Data {
        var bytes = [UInt8](repeating: 0, count: byteCount)
        let status = SecRandomCopyBytes(kSecRandomDefault, byteCount, &bytes)
        guard status == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        return Data(bytes)
    }

    /// Generates a cryptographically secure random token as a hex string.
    func generateSecureToken(byteCount: Int = 32) throws -> String {
        let data = try generateSecureRandomData(byteCount: byteCount)
        return data.map { String(format: "%02x", $0) }.joined()
    }
}

// MARK: - Secure Local Storage

/// Provides a high-level API for storing and retrieving encrypted data on disk.
/// Files are stored in the app's Application Support directory with Data Protection.
final class SecureLocalStorage {

    static let shared = SecureLocalStorage()

    private let securityModule = DataSecurityModule.shared
    private let fileManager = FileManager.default

    private var storageDirectory: URL {
        let appSupport = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        let secureDir = appSupport.appendingPathComponent("SecureStorage", isDirectory: true)

        if !fileManager.fileExists(atPath: secureDir.path) {
            try? fileManager.createDirectory(at: secureDir, withIntermediateDirectories: true, attributes: [
                .protectionKey: FileProtectionType.completeUntilFirstUserAuthentication
            ])
        }

        return secureDir
    }

    private init() {}

    // MARK: - Store Encrypted Data

    /// Stores a `Codable` object encrypted on disk.
    func store<T: Codable>(_ object: T, withKey key: String, dataType: SensitiveDataType) throws {
        let encryptedData = try securityModule.encrypt(object: object, for: dataType)
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtectionUntilFirstUserAuthentication])
    }

    /// Stores a `String` encrypted on disk.
    func store(string: String, withKey key: String, dataType: SensitiveDataType) throws {
        let encryptedData = try securityModule.encrypt(string: string, for: dataType)
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtectionUntilFirstUserAuthentication])
    }

    // MARK: - Retrieve Encrypted Data

    /// Retrieves and decrypts a `Codable` object from disk.
    func retrieve<T: Codable>(as type: T.Type, withKey key: String, dataType: SensitiveDataType) throws -> T {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        let encryptedData = try Data(contentsOf: fileURL)
        return try securityModule.decrypt(data: encryptedData, as: type, for: dataType)
    }

    /// Retrieves and decrypts a `String` from disk.
    func retrieveString(withKey key: String, dataType: SensitiveDataType) throws -> String {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        let encryptedData = try Data(contentsOf: fileURL)
        return try securityModule.decryptToString(data: encryptedData, for: dataType)
    }

    // MARK: - Delete

    /// Deletes a stored item.
    func delete(key: String) throws {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
        }
    }

    /// Checks if an item exists.
    func exists(key: String) -> Bool {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        return fileManager.fileExists(atPath: fileURL.path)
    }

    /// Deletes all stored data and encryption keys.
    func purgeAll() throws {
        if fileManager.fileExists(atPath: storageDirectory.path) {
            try fileManager.removeItem(at: storageDirectory)
        }
        try KeychainKeyManager.shared.deleteAllKeys()
    }
}

// MARK: - String Extension for Hashing File Names

private extension String {
    var sha256Hash: String {
        let data = Data(self.utf8)
        let hash = SHA256.hash(data: data)
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
}

